function Greeting({ name }) {
  return (
    <div className="greeting">
      <h1>Hello, {name}!</h1>
      <p>Welcome to React.</p>
    </div>
  );
}

export default Greeting;

.container {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  grid-template-rows: auto;
  gap: 20px;
}

.hero-item {
  grid-column: 1 / 3; /* spans columns 1 to 3 */
  grid-row: 1 / 2;
}

let name: string = 'Shiva';
let age: number = 25;
let isDeveloper: boolean = true;
let skills: string[] = ['React', 'TypeScript', 'CSS'];

interface BlogPost {
  id: string;
  title: string;
  author: string;
  date: string;
  tags: string[];
}

function renderPost(post: BlogPost): string {
  return `<h1>${post.title}</h1>`;
}
